import{_ as e,o,c as r,ag as i}from"./chunks/framework.6MCaaFDc.js";const m=JSON.parse('{"title":"Environment & Society","description":"","frontmatter":{},"headers":[],"relativePath":"theory/social/environment-society.md","filePath":"theory/social/environment-society.md"}'),n={name:"theory/social/environment-society.md"};function a(s,t,l,d,c,g){return o(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="environment-society" tabindex="-1">Environment &amp; Society <a class="header-anchor" href="#environment-society" aria-label="Permalink to &quot;Environment &amp; Society&quot;">​</a></h1><p>Technology powers the modern world — but at a cost. The devices we use daily consume enormous energy, create hazardous waste, and contribute to carbon emissions. At the same time, ICT offers powerful tools for addressing environmental challenges. Understanding both sides is essential for responsible digital citizenship.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 12</p><p>Environmental impact of ICT, distributed computing, and AI/robotics in society are primarily Grade 12 topics.</p></div><hr><h2 id="environmental-impact-of-ict" tabindex="-1">Environmental Impact of ICT <a class="header-anchor" href="#environmental-impact-of-ict" aria-label="Permalink to &quot;Environmental Impact of ICT&quot;">​</a></h2><h3 id="e-waste-—-electronic-waste" tabindex="-1">E-waste — Electronic Waste <a class="header-anchor" href="#e-waste-—-electronic-waste" aria-label="Permalink to &quot;E-waste — Electronic Waste&quot;">​</a></h3><p><strong>E-waste</strong> is discarded electronic equipment — old phones, computers, TVs, batteries, and other electronics.</p><p><strong>Why e-waste is a serious problem:</strong></p><ul><li>Electronics contain <strong>toxic materials</strong>: lead, mercury, cadmium, beryllium, arsenic</li><li>These leach into soil and groundwater at landfill sites</li><li>Informal e-waste &quot;recycling&quot; in developing countries exposes workers to toxins</li><li>E-waste is the fastest-growing waste stream globally</li><li>SA generates over 350,000 tonnes of e-waste per year</li></ul><table tabindex="0"><thead><tr><th>Toxic material</th><th>Found in</th><th>Effect</th></tr></thead><tbody><tr><td><strong>Lead</strong></td><td>Solder, CRT screens</td><td>Damages nervous system and kidneys</td></tr><tr><td><strong>Mercury</strong></td><td>LCD backlights, batteries</td><td>Damages brain and nervous system</td></tr><tr><td><strong>Cadmium</strong></td><td>Rechargeable batteries</td><td>Causes cancer, kidney damage</td></tr><tr><td><strong>Beryllium</strong></td><td>Connectors</td><td>Causes lung disease</td></tr><tr><td><strong>Flame retardants</strong></td><td>Circuit boards</td><td>Hormone disruptors</td></tr></tbody></table><h3 id="responsible-e-waste-management" tabindex="-1">Responsible E-waste Management: <a class="header-anchor" href="#responsible-e-waste-management" aria-label="Permalink to &quot;Responsible E-waste Management:&quot;">​</a></h3><ul><li><strong>Recycle</strong> through certified e-waste collection points</li><li><strong>Donate</strong> working devices instead of discarding</li><li><strong>Buy refurbished</strong> — extend device lifespan</li><li><strong>Manufacturer take-back</strong> — some brands accept old devices</li><li><strong>Certified recyclers</strong> — Waste Electrical and Electronic Equipment (WEEE)</li></ul><hr><h3 id="energy-consumption" tabindex="-1">Energy Consumption <a class="header-anchor" href="#energy-consumption" aria-label="Permalink to &quot;Energy Consumption&quot;">​</a></h3><p>ICT uses enormous amounts of electricity:</p><table tabindex="0"><thead><tr><th>Source</th><th>Consumption</th></tr></thead><tbody><tr><td>Data centres</td><td>~1–2% of global electricity</td></tr><tr><td>Networks (routers, towers)</td><td>~1% of global electricity</td></tr><tr><td>User devices</td><td>~2% of global electricity</td></tr><tr><td><strong>Total ICT</strong></td><td>~4–5% of global electricity</td></tr></tbody></table><p><strong>Data centres:</strong></p><ul><li>Google, Amazon, Meta, and Microsoft operate hundreds of data centres globally</li><li>A large data centre uses as much electricity as a small city</li><li>Require constant cooling — additional energy cost</li><li>Google has committed to 100% renewable energy</li></ul><p><strong>Bitcoin and cryptocurrency:</strong></p><ul><li>Proof-of-work mining extremely energy intensive</li><li>Bitcoin network uses ~120 TWh/year — more than Argentina</li></ul><h3 id="green-ict-solutions" tabindex="-1">Green ICT Solutions: <a class="header-anchor" href="#green-ict-solutions" aria-label="Permalink to &quot;Green ICT Solutions:&quot;">​</a></h3><ul><li><strong>Renewable energy</strong> — solar/wind powered data centres</li><li><strong>Energy-efficient hardware</strong> — ARM processors, efficient SSDs</li><li><strong>Virtualisation</strong> — fewer physical servers needed</li><li><strong>Cloud computing</strong> — better utilisation of shared infrastructure</li><li><strong>Power management</strong> — sleep modes, automatic shutdown</li></ul><hr><h3 id="carbon-footprint-of-ict" tabindex="-1">Carbon Footprint of ICT <a class="header-anchor" href="#carbon-footprint-of-ict" aria-label="Permalink to &quot;Carbon Footprint of ICT&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Device</th><th>Estimated CO₂ for manufacturing</th></tr></thead><tbody><tr><td>Smartphone</td><td>~70 kg CO₂</td></tr><tr><td>Laptop</td><td>~300–400 kg CO₂</td></tr><tr><td>Desktop PC</td><td>~400–600 kg CO₂</td></tr><tr><td>Server</td><td>~1–2 tonnes CO₂</td></tr></tbody></table><p><strong>Key insight:</strong> Most of a device&#39;s carbon footprint comes from <strong>manufacturing</strong>, not use. Keeping devices longer significantly reduces your carbon impact.</p><p><strong>Actions that help:</strong></p><ul><li>Keep devices longer before replacing</li><li>Buy refurbished/second-hand devices</li><li>Choose energy-efficient models</li><li>Recycle properly</li></ul><hr><h2 id="ict-and-society" tabindex="-1">ICT and Society <a class="header-anchor" href="#ict-and-society" aria-label="Permalink to &quot;ICT and Society&quot;">​</a></h2><h3 id="ai-and-automation" tabindex="-1">AI and Automation <a class="header-anchor" href="#ai-and-automation" aria-label="Permalink to &quot;AI and Automation&quot;">​</a></h3><p><strong>Artificial Intelligence (AI)</strong> is the ability of computer systems to perform tasks that normally require human intelligence.</p><table tabindex="0"><thead><tr><th>AI Application</th><th>Industry</th><th>Impact</th></tr></thead><tbody><tr><td>Medical diagnosis</td><td>Healthcare</td><td>AI detects cancer in images with &gt;90% accuracy</td></tr><tr><td>Customer service</td><td>Retail/banking</td><td>Chatbots handle routine queries</td></tr><tr><td>Fraud detection</td><td>Finance</td><td>Real-time transaction analysis</td></tr><tr><td>Content recommendation</td><td>Entertainment</td><td>Netflix, Spotify, YouTube algorithms</td></tr><tr><td>Autonomous vehicles</td><td>Transport</td><td>Self-driving cars, trucks</td></tr><tr><td>Language translation</td><td>Communication</td><td>Google Translate</td></tr><tr><td>Writing assistance</td><td>Many</td><td>AI-generated text (ChatGPT)</td></tr></tbody></table><p><strong>Positive impacts of AI:</strong></p><ul><li>Improves medical diagnosis accuracy</li><li>Reduces human error in dangerous or repetitive tasks</li><li>Makes personalised services possible at scale</li><li>Solves complex optimisation problems (logistics, energy)</li></ul><p><strong>Negative impacts of AI:</strong></p><ul><li>Job displacement — routine tasks automated</li><li>Algorithmic bias — AI can discriminate</li><li>Deepfakes — AI-generated misinformation</li><li>Privacy concerns — AI requires vast data</li><li>Autonomous weapons — ethical issues around AI in warfare</li></ul><hr><h3 id="robotics" tabindex="-1">Robotics <a class="header-anchor" href="#robotics" aria-label="Permalink to &quot;Robotics&quot;">​</a></h3><p><strong>Robots</strong> are programmable machines capable of carrying out complex actions automatically.</p><table tabindex="0"><thead><tr><th>Sector</th><th>Use</th><th>Impact</th></tr></thead><tbody><tr><td><strong>Manufacturing</strong></td><td>Assembly lines, welding, painting</td><td>Replaced many factory workers</td></tr><tr><td><strong>Logistics</strong></td><td>Warehouse picking, delivery drones</td><td>Amazon, DHL use robots</td></tr><tr><td><strong>Healthcare</strong></td><td>Surgical robots, pharmacy robots</td><td>More precise surgery</td></tr><tr><td><strong>Agriculture</strong></td><td>Automated harvesting, planting</td><td>Addresses labour shortage</td></tr><tr><td><strong>Mining</strong></td><td>Autonomous vehicles, drilling</td><td>Reduces danger to workers</td></tr><tr><td><strong>Domestic</strong></td><td>Robot vacuum cleaners</td><td>Household convenience</td></tr></tbody></table><p><strong>Advantages of robots:</strong></p><ul><li>Work 24/7 without fatigue</li><li>No human error in repetitive tasks</li><li>Safe in hazardous environments</li><li>More consistent quality</li></ul><p><strong>Disadvantages:</strong></p><ul><li>High capital cost</li><li>Job displacement — fewer factory/manual jobs</li><li>Cannot handle unpredictable situations (yet)</li><li>Maintenance costs</li></ul><hr><h3 id="distributed-computing" tabindex="-1">Distributed Computing <a class="header-anchor" href="#distributed-computing" aria-label="Permalink to &quot;Distributed Computing&quot;">​</a></h3><p><strong>Distributed computing</strong> uses multiple computers networked together to solve a large computing problem — each handles a portion of the work.</p><p><strong>Examples:</strong></p><ul><li><strong>BOINC / SETI@home</strong> — volunteer computers helping analyse radio telescope data</li><li><strong>Folding@home</strong> — protein folding simulations for disease research</li><li><strong>Blockchain</strong> — distributed ledger across thousands of computers</li><li><strong>Grid computing</strong> — research institutions sharing computing power</li></ul><p><strong>Benefits:</strong></p><ul><li>Harnesses unused computing power of millions of devices</li><li>Solves problems too large for any single computer</li><li>Cost-effective — uses existing volunteer hardware</li><li>Resilient — no single point of failure</li></ul><hr><h3 id="ict-in-developing-countries" tabindex="-1">ICT in Developing Countries <a class="header-anchor" href="#ict-in-developing-countries" aria-label="Permalink to &quot;ICT in Developing Countries&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Application</th><th>Impact</th></tr></thead><tbody><tr><td><strong>Mobile banking</strong></td><td>M-Pesa (Kenya) — financial services without formal banks</td></tr><tr><td><strong>Agricultural information</strong></td><td>Market prices via SMS — farmers get fair prices</td></tr><tr><td><strong>Healthcare</strong></td><td>Telemedicine in areas without doctors</td></tr><tr><td><strong>Education</strong></td><td>Online learning reaching remote schools</td></tr><tr><td><strong>E-government</strong></td><td>Digital identity, online services, reducing corruption</td></tr></tbody></table><p><strong>South African examples:</strong></p><ul><li>E-filing (SARS) — tax returns online</li><li>HealthConnect — mHealth initiatives</li><li>eSchool / Vodacom e-School — learning platforms</li><li>National Health Insurance (NHI) digital systems</li></ul><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>E-waste</strong></td><td>Discarded electronic equipment</td></tr><tr><td><strong>Carbon footprint</strong></td><td>Total greenhouse gas emissions from an activity</td></tr><tr><td><strong>Green ICT</strong></td><td>Environmentally responsible use of technology</td></tr><tr><td><strong>AI</strong></td><td>Artificial Intelligence — computer systems performing tasks requiring human intelligence</td></tr><tr><td><strong>Robotics</strong></td><td>Programming and use of machines to perform complex actions</td></tr><tr><td><strong>Distributed computing</strong></td><td>Multiple networked computers solving one large problem</td></tr><tr><td><strong>Automation</strong></td><td>Using technology to perform tasks previously done by humans</td></tr><tr><td><strong>Blockchain</strong></td><td>Distributed ledger across many computers</td></tr><tr><td><strong>Deepfake</strong></td><td>AI-generated fake video or image of a real person</td></tr><tr><td><strong>Algorithmic bias</strong></td><td>AI producing unfair results due to biased training data</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;What is e-waste? Give TWO toxic materials found in e-waste and their effects.&quot;</strong> — Discarded electronic equipment; lead: damages nervous system; mercury: damages brain; cadmium: causes cancer and kidney damage</p></li><li><p><strong>&quot;Give THREE ways individuals can reduce the environmental impact of ICT&quot;</strong> — keep devices longer; buy refurbished; recycle at certified e-waste facilities; use energy-efficient settings; choose renewable energy</p></li><li><p><strong>&quot;Give TWO advantages and TWO disadvantages of robotics in manufacturing&quot;</strong> — Advantages: work 24/7, consistent quality, safer in hazardous conditions; Disadvantages: high cost, job displacement, cannot handle unpredictable situations</p></li><li><p><strong>&quot;What is distributed computing? Give ONE example.&quot;</strong> — Multiple networked computers solving one large problem; examples: BOINC/SETI@home (analysing telescope data), Folding@home (protein research), blockchain</p></li><li><p><strong>&quot;Give TWO negative impacts of AI on society&quot;</strong> — job displacement as automation replaces human workers; algorithmic bias leading to discrimination; deepfakes spreading misinformation; privacy concerns from data requirements</p></li></ol></div>',63)])])}const h=e(n,[["render",a]]);export{m as __pageData,h as default};
